    <script>
        document.addEventListener('DOMContentLoaded', function() {
            // --- Biểu thức chính quy ---
            const regex = /serial[:：]\s*([^\n]*)\s*time[:：]\s*([^\n]*)(?:\s*NSFW[:：]\s*([\s\S]*?))?\s*scene[:：]\s*([\s\S]*?)\s*plot[:：]\s*([\s\S]*?)(?:\s*relation[:：]\s*([\s\S]*?))?(?:\s*echoes[:：]\s*([\s\S]*?))?(?:\s*archived[:：]\s*([\s\S]*?))?(?:\s*enigma[:：]\s*([\s\S]*?))?(?:\s*seeds[:：]\s*([\s\S]*))?$/i;

            function parseAndRender() {
                const rawDataElement = document.querySelector('.raw-data');
                if (!rawDataElement || !rawDataElement.textContent.trim()) return;

                const rawText = rawDataElement.textContent.trim();
                const match = rawText.match(regex);

                if (match) {
                    const [_, serial, time, nsfw, scene, plot, relation, echoes, archived, enigma, seeds] = match;

                    // --- Header ---
                    document.querySelector('.serial').textContent = serial.trim();
                    document.querySelector('.time').textContent = time.trim();
                    const nsfwTag = document.querySelector('.nsfw-tag');
                    if (nsfw && nsfw.trim() && nsfw.trim()[0] !== '0') {
                        nsfwTag.textContent = "NSFW " + nsfw.trim();
                        nsfwTag.style.display = 'inline-block';
                    } else { nsfwTag.style.display = 'none'; }

                    // --- Scene & Plot ---
                    document.querySelector('.plot-content').textContent = plot.trim();
                    const sceneContent = document.querySelector('.scene-content');
                    sceneContent.innerHTML = '';
                    scene.trim().split('\n').forEach(line => {
                        const p = document.createElement('p');
                        p.textContent = line.trim();
                        if (line.includes('【')) p.style.color = 'var(--text-accent)';
                        sceneContent.appendChild(p);
                    });

                    // --- Relation ---
                    const relationMod = document.getElementById('mod-relation');
                    if (relation && relation.trim()) {
                        relationMod.style.display = 'block';
                        const container = relationMod.querySelector('.relation-content');
                        container.innerHTML = '';
                        relation.trim().split('◈').forEach(chunk => {
                            if (!chunk.trim()) return;
                            const card = document.createElement('div');
                            card.className = 'char-card';
                            const lines = chunk.trim().split('\n');
                            card.innerHTML = `<div class="char-head">${lines[0].trim()}</div><div class="char-body">${lines.slice(1).join('<br>')}</div>`;
                            container.appendChild(card);
                        });
                    } else { relationMod.style.display = 'none'; }

                    // --- Echoes ---
                    const echoesMod = document.getElementById('mod-echoes');
                    if (echoes && echoes.trim()) {
                        const echoLines = echoes.trim().split('\n').filter(line => line.trim().startsWith('-'));
                        if(echoLines.length > 0) {
                            echoesMod.style.display = 'block';
                            const container = echoesMod.querySelector('.echoes-content');
                            container.innerHTML = '';
                            echoLines.forEach(line => {
                                const content = line.substring(1).trim();
                                const colonIndex = content.search(/[:：]/);
                                if (colonIndex > 0) {
                                    const speaker = content.substring(0, colonIndex).trim();
                                    const quote = content.substring(colonIndex + 1).trim();
                                    const item = document.createElement('div');
                                    item.className = 'echo-item';
                                    item.innerHTML = `<span class="echo-quote">“${quote}”</span><span class="echo-speaker">— ${speaker}</span>`;
                                    container.appendChild(item);
                                }
                            });
                        } else { echoesMod.style.display = 'none'; }
                    } else { echoesMod.style.display = 'none'; }

                    // --- [Sửa chữa] Hàm render module có thể mở rộng ---
                    const setupDetailsModule = (moduleKey, content) => {
                        const mod = document.getElementById(`mod-${moduleKey}`);
                        if (content && content.trim()) {
                            mod.style.display = 'block';
                            const container = mod.querySelector(`.${moduleKey}-content`);
                            container.innerHTML = '';
                            content.trim().split('\n').forEach(line => {
                                const p = document.createElement('p');
                                const text = line.trim();
                                // Phân biệt dòng tiêu đề và dòng nội dung
                                if (text.startsWith('-')) {
                                    p.className = 'item'; // Dòng nội dung
                                    p.textContent = text.substring(1).trim(); // Bỏ dấu '-'
                                } else {
                                    p.className = 'title'; // Dòng tiêu đề
                                    p.textContent = text;
                                }
                                container.appendChild(p);
                            });
                        } else { mod.style.display = 'none'; }
                    };
                    setupDetailsModule('archived', archived);
                    setupDetailsModule('enigma', enigma);
                    setupDetailsModule('seeds', seeds);

                } else {
                    console.error("Không thể phân tích nội dung trong raw-data. Vui lòng kiểm tra định dạng Prompt.");
                    document.querySelector('.plot-content').textContent = "Phân tích dữ liệu thất bại, vui lòng kiểm tra định dạng.";
                }
            }

            // --- Tương tác và Hiệu ứng Trang (Không thay đổi) ---
            const body = document.body;
            const header = document.getElementById('meow-toggle-header');
            const collapsibleContent = document.getElementById('meow-collapsible-content');
            const buttonText = document.getElementById('expand-button-text');
            const themeToggle = document.getElementById('theme-toggle-checkbox');
            const particlesContainer = document.getElementById('particles-js');

            function createParticles(theme) {
                if (!particlesContainer) return;
                particlesContainer.innerHTML = '';
                const isDark = theme === 'dark';
                const particleCount = isDark ? 25 : 40;
                const lightParticleColors = ['rgba(192, 168, 133, 0.6)', 'rgba(113, 128, 150, 0.6)', 'rgba(255, 255, 255, 0.7)'];
                const darkParticleColors = ['rgba(204, 165, 106, 0.5)'];
                const colors = isDark ? darkParticleColors : lightParticleColors;
                for (let i = 0; i < particleCount; i++) {
                    let particle = document.createElement('div');
                    Object.assign(particle.style, { position: 'absolute', borderRadius: '50%', background: colors[Math.floor(Math.random() * colors.length)] });
                    if (isDark) particle.style.boxShadow = `0 0 8px ${particle.style.background}, 0 0 4px ${particle.style.background}`;
                    const size = isDark ? (Math.random() * 2.5 + 1) : (Math.random() * 3 + 1.5);
                    Object.assign(particle.style, { width: `${size}px`, height: `${size}px`, left: `${Math.random() * 100}%`, top: `${Math.random() * 100}%` });
                    particle.animate([{ transform: `translate(0, 0)`, opacity: Math.random() * 0.7 + 0.2 }, { transform: `translate(${(Math.random() - 0.5) * (isDark ? 40 : 80)}px, ${(Math.random() - 0.5) * (isDark ? -150 : 80)}px)`, opacity: 0 }], { duration: Math.random() * (isDark ? 15000 : 8000) + (isDark ? 10000 : 5000), iterations: Infinity, easing: isDark ? 'ease-in' : 'cubic-bezier(0.25, 0.1, 0.25, 1.0)', delay: -Math.random() * (isDark ? 25000 : 0) });
                    particlesContainer.appendChild(particle);
                }
            }

            function setTheme(theme) {
                body.classList.toggle('dark-mode', theme === 'dark');
                document.querySelector('.footer-light').style.display = theme === 'dark' ? 'none' : 'block';
                document.querySelector('.footer-dark').style.display = theme === 'dark' ? 'block' : 'none';
                themeToggle.checked = theme === 'dark';
                localStorage.setItem('summary-theme-preference', theme);
                createParticles(theme);
            }

            header.addEventListener('click', (e) => {
                if(e.target.closest('.theme-switch-wrapper')) return;
                collapsibleContent.classList.toggle('open');
                buttonText.textContent = collapsibleContent.classList.contains('open') ? 'Niêm Phong Hồi Âm…' : 'Gõ Cửa Tháp…';
            });

            document.querySelectorAll('.details-box').forEach(el => {
                el.addEventListener('click', (event) => event.stopPropagation());
            });

            themeToggle.addEventListener('change', () => { setTheme(themeToggle.checked ? 'dark' : 'light'); });

            parseAndRender();
            const savedTheme = localStorage.getItem('summary-theme-preference') || 'light';
            setTheme(savedTheme);
        });
    </script>
</body>
</html>
