async function updateButtonStates(sourceSettings = settings) {
    if (!panel)
        return;
    panel.find('button[data-setting]').each((_, el) => {
        const btn = $(el);
        const setting = btn.data('setting');
        const value = btn.data('value');
        btn.toggleClass('active', sourceSettings[setting] === value);
    });
}
