        return;
    panel.find('button[data-panel]').on('click', (e) => {
        const panelId = $(e.currentTarget).data('panel');
        if (panelId === 'requests') {
            panel?.find('.panel-child[data-panel-id="requests"] button').each(function () {
                const buttonText = $(this).clone().children().remove().end().text().trim();
                if (!$(this).data('action')) {
                    let actionKey = '';
                    switch (buttonText) {
                        case 'Dẫn Chuyện Nhanh': actionKey = 'qr_quick_narrate'; break;
                        case 'Dẫn Chuyện Chậm': actionKey = 'qr_slow_narrate'; break;
                        case 'Cấm Lặp Lại': actionKey = 'qr_no_repeat'; break;
                        case 'Cấm Nhảy Tin Nhắn': actionKey = 'qr_no_skip'; break;
                        case 'Quét Lại Quy Tắc': actionKey = 'qr_rescan'; break;
                        case 'Cập Nhật Bảng': actionKey = 'qr_update_table'; break;
                        case 'Cập Nhật Thanh Trạng Thái': actionKey = 'qr_update_status'; break;
                        case 'Tạo Định Dạng Điện Thoại': actionKey = 'qr_gen_mobile'; break;
                        case 'Xuất Tiểu Kịch Trường': actionKey = 'qr_output_theater'; break;
                        case 'Tùy Chỉnh': actionKey = 'custom_request'; break;
                    }
                    if (actionKey) {
                        $(this).attr('data-action', actionKey);
