        renderStatusDisplay(); // 返回主菜单时刷新状态
    });
    panel.find('.close-button').on('click', hidePanel);
    panel.find('#theme-toggle-button').on('click', toggleTheme);
    panel.on('click', 'button[data-action]', async (e) => {
        const action = $(e.currentTarget).data('action');
        if (action in summaryActions) {
            hidePanel();
            await summaryActions[action]();
        }
        else if (action in quickRequestActions) {
            hidePanel();
            await handleQuickRequest(action);
        }
        switch (action) {
            case 'reset_settings': {
                if (window.confirm('Bạn có chắc muốn khôi phục tất cả cài đặt về giá trị mặc định không? Thao tác này không thể đảo ngược.')) {
                    await renderPresetPanel(defaultSettings);
                    toastr.info('Cài đặt đã được đặt lại về mặc định trên bảng điều khiển. Vui lòng nhấp "Lưu và thêm vào" để thay đổi có hiệu lực.');
