                updateThemeToggleButton();
                break;
            }
            case 'force_save': {
                console.log('Tòa Tawa QR [Lưu bắt buộc]: Bắt đầu thu thập cài đặt từ UI.');
                const newSettings = JSON.parse(JSON.stringify(defaultSettings));
                newSettings.wordCount = {
                    min: parseInt(panel?.find('#wc-min').val()) || 0,
                    max: parseInt(panel?.find('#wc-max').val()) || 0,
                };
                newSettings.paragraphCount = {
                    min: parseInt(panel?.find('#pc-min').val()) || 0,
                    max: parseInt(panel?.find('#pc-max').val()) || 0,
                };
                panel?.find('.setting-group').each(function () {
                    const activeBtn = $(this).find('button[data-setting].active');
                    if (activeBtn.length > 0) {
                        const setting = activeBtn.data('setting');
                        const value = activeBtn.data('value');
                        if (setting && value) {
                            newSettings[setting] = value;
                        }
                    }
                });
                newSettings.autoTheme = settings.autoTheme;
                newSettings.theme = settings.theme;
                console.log('Tòa Tawa QR [Lưu bắt buộc]: Thu thập UI hoàn tất, chuẩn bị lưu trữ bền vững:', newSettings);
                updateVariablesWith(vars => {
                    Object.keys(vars).forEach(key => delete vars[key]);
                    Object.assign(vars, newSettings, { initialized: true });
                    console.log('Tòa Tawa QR [Lưu bắt buộc]: Đang thực hiện ghi lưu trữ bền vững:', vars);
