        $('body').append($popup);
        console.log('Tòa Tawa QR: Welcome popup appended to body.');
        setTimeout(() => {
            $popup.addClass('visible');
            console.log('Tòa Tawa QR: Welcome popup is now visible.');
        }, 50);
        $popup.find('#qr-go-to-settings').on('click', async () => {
            console.log('Tòa Tawa QR: "Đi tới cài đặt" clicked.');
            $popup.removeClass('visible');
            console.log('Tòa Tawa QR: Welcome popup visibility removed.');
            setTimeout(() => {
                $popup.remove();
                console.log('Tòa Tawa QR: Welcome popup removed from DOM.');
            }, 300);
            await showPanel(true);
            console.log('Tòa Tawa QR: showPanel called for presets.');
        });
    }
    else {
        console.log('Tòa Tawa QR: Found saved settings, loading them.');
        loadSettings();
    }
}
