            }

            // --- Tương tác và Hiệu ứng Trang (Không thay đổi) ---
            const body = document.body;
            const header = document.getElementById('meow-toggle-header');
            const collapsibleContent = document.getElementById('meow-collapsible-content');
            const buttonText = document.getElementById('expand-button-text');
            const themeToggle = document.getElementById('theme-toggle-checkbox');
            const particlesContainer = document.getElementById('particles-js');

            function createParticles(theme) {
                if (!particlesContainer) return;
                particlesContainer.innerHTML = '';
                const isDark = theme === 'dark';
                const particleCount = isDark ? 25 : 40;
                const lightParticleColors = ['rgba(192, 168, 133, 0.6)', 'rgba(113, 128, 150, 0.6)', 'rgba(255, 255, 255, 0.7)'];
                const darkParticleColors = ['rgba(204, 165, 106, 0.5)'];
                const colors = isDark ? darkParticleColors : lightParticleColors;
                for (let i = 0; i < particleCount; i++) {
                    let particle = document.createElement('div');
                    Object.assign(particle.style, { position: 'absolute', borderRadius: '50%', background: colors[Math.floor(Math.random() * colors.length)] });
                    if (isDark) particle.style.boxShadow = `0 0 8px ${particle.style.background}, 0 0 4px ${particle.style.background}`;
                    const size = isDark ? (Math.random() * 2.5 + 1) : (Math.random() * 3 + 1.5);
                    Object.assign(particle.style, { width: `${size}px`, height: `${size}px`, left: `${Math.random() * 100}%`, top: `${Math.random() * 100}%` });
                    particle.animate([{ transform: `translate(0, 0)`, opacity: Math.random() * 0.7 + 0.2 }, { transform: `translate(${(Math.random() - 0.5) * (isDark ? 40 : 80)}px, ${(Math.random() - 0.5) * (isDark ? -150 : 80)}px)`, opacity: 0 }], { duration: Math.random() * (isDark ? 15000 : 8000) + (isDark ? 10000 : 5000), iterations: Infinity, easing: isDark ? 'ease-in' : 'cubic-bezier(0.25, 0.1, 0.25, 1.0)', delay: -Math.random() * (isDark ? 25000 : 0) });
                    particlesContainer.appendChild(particle);
                }
            }

            function setTheme(theme) {
                body.classList.toggle('dark-mode', theme === 'dark');
                document.querySelector('.footer-light').style.display = theme === 'dark' ? 'none' : 'block';
                document.querySelector('.footer-dark').style.display = theme === 'dark' ? 'block' : 'none';
                themeToggle.checked = theme === 'dark';
                localStorage.setItem('summary-theme-preference', theme);
                createParticles(theme);
            }

            header.addEventListener('click', (e) => {
                if(e.target.closest('.theme-switch-wrapper')) return;
                collapsibleContent.classList.toggle('open');
                buttonText.textContent = collapsibleContent.classList.contains('open') ? 'Niêm Phong Hồi Âm…' : 'Gõ Cửa Tháp…';
            });

            document.querySelectorAll('.details-box').forEach(el => {
                el.addEventListener('click', (event) => event.stopPropagation());
            });

            themeToggle.addEventListener('change', () => { setTheme(themeToggle.checked ? 'dark' : 'light'); });

            parseAndRender();
            const savedTheme = localStorage.getItem('summary-theme-preference') || 'light';
            setTheme(savedTheme);
        });
    </script>
